from flask import Flask, request, jsonify, redirect
import secrets
import hashlib
import time

app = Flask(__name__)

# Storage
auth_codes = {}  # code_hash -> {'user_id': user_id, 'client_id': client_id, 'used': False, 'created_at': timestamp}
access_tokens = {}  # token -> {'user_id': user_id, 'client_id': client_id, 'created_at': timestamp}
clients = {
    'client123': {
        'client_secret': 'secret123',
        'redirect_uris': ['http://localhost:5001/callback']
    }
}

CODE_EXPIRATION = 600  # 10 minutes
TOKEN_EXPIRATION = 3600  # 1 hour

def hash_code(code):
    return hashlib.sha256(code.encode()).hexdigest()

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    state = request.args.get('state', '')
    
    if not client_id or client_id not in clients:
        return jsonify({'error': 'invalid_client'}), 400
    
    if redirect_uri not in clients[client_id]['redirect_uris']:
        return jsonify({'error': 'invalid_redirect_uri'}), 400
    
    # Simulate user authentication and consent
    user_id = 'user123'
    
    # Generate authorization code
    code = secrets.token_urlsafe(32)
    code_hash = hash_code(code)
    
    auth_codes[code_hash] = {
        'user_id': user_id,
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'used': False,
        'created_at': time.time()
    }
    
    # Redirect back to client with code
    separator = '&' if '?' in redirect_uri else '?'
    return redirect(f"{redirect_uri}{separator}code={code}&state={state}")

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    redirect_uri = request.form.get('redirect_uri')
    
    if grant_type != 'authorization_code':
        return jsonify({'error': 'unsupported_grant_type'}), 400
    
    # Validate client credentials
    if not client_id or client_id not in clients:
        return jsonify({'error': 'invalid_client'}), 401
    
    if clients[client_id]['client_secret'] != client_secret:
        return jsonify({'error': 'invalid_client'}), 401
    
    if not code:
        return jsonify({'error': 'invalid_request'}), 400
    
    code_hash = hash_code(code)
    
    # Validate authorization code
    if code_hash not in auth_codes:
        return jsonify({'error': 'invalid_grant'}), 400
    
    code_data = auth_codes[code_hash]
    
    # Check if code has expired
    if time.time() - code_data['created_at'] > CODE_EXPIRATION:
        del auth_codes[code_hash]
        return jsonify({'error': 'invalid_grant'}), 400
    
    # Validate client_id matches
    if code_data['client_id'] != client_id:
        return jsonify({'error': 'invalid_grant'}), 400
    
    # Validate redirect_uri matches
    if code_data['redirect_uri'] != redirect_uri:
        return jsonify({'error': 'invalid_grant'}), 400
    
    # Check if code has already been used (prevent replay attacks)
    if code_data['used']:
        # Code reuse detected - revoke all tokens for this user/client
        tokens_to_revoke = [token for token, data in access_tokens.items() 
                           if data['user_id'] == code_data['user_id'] 
                           and data['client_id'] == client_id]
        for token in tokens_to_revoke:
            del access_tokens[token]
        
        del auth_codes[code_hash]
        return jsonify({'error': 'invalid_grant'}), 400
    
    # Mark code as used
    code_data['used'] = True
    
    # Generate access token
    access_token = secrets.token_urlsafe(32)
    access_tokens[access_token] = {
        'user_id': code_data['user_id'],
        'client_id': client_id,
        'created_at': time.time()
    }
    
    # Delete the authorization code after successful use
    del auth_codes[code_hash]
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': TOKEN_EXPIRATION
    })

@app.route('/validate', methods=['POST'])
def validate():
    token = request.form.get('token')
    
    if not token or token not in access_tokens:
        return jsonify({'error': 'invalid_token'}), 401
    
    token_data = access_tokens[token]
    
    # Check if token has expired
    if time.time() - token_data['created_at'] > TOKEN_EXPIRATION:
        del access_tokens[token]
        return jsonify({'error': 'token_expired'}), 401
    
    return jsonify({
        'valid': True,
        'user_id': token_data['user_id'],
        'client_id': token_data['client_id']
    })

